export const Controlled = () => {
  const [page, setPage] = useState(1);
  const pageSize = 10;
  const count = 100;

  return (
    <Stack gap={4}>
      <Text>
        Current Page: {page} of {Math.ceil(count / pageSize)}
      </Text>
      <Pagination
        count={count}
        pageSize={pageSize}
        page={page}
        onPageChange={(e) => setPage(e.page)}
      >
        <HStack gap={2}>
          <PaginationPrevTrigger>
            <Button variant="outline" size="sm">
              Previous
            </Button>
          </PaginationPrevTrigger>
          <PaginationItems
            render={(page) => (
              <Button
                key={page.value}
                variant={page.type === "page" ? "outline" : "ghost"}
                size="sm"
              >
                {page.type === "ellipsis" ? "..." : page.value}
              </Button>
            )}
          />
          <PaginationNextTrigger>
            <Button variant="outline" size="sm">
              Next
            </Button>
          </PaginationNextTrigger>
        </HStack>
      </Pagination>
    </Stack>
  );
};

